import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getChanson } from '../api/chansonService';
import { getAlbums } from '../api/albumService';

export default function ChansonDetail() {
  const { id } = useParams();
  const [chanson, setChanson] = useState(null);
  const [album, setAlbum] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    let fetchedChanson;

    getChanson(id)
      .then((response) => {
        fetchedChanson = response.data || null;
        setChanson(fetchedChanson);
        return fetchedChanson?.albumId ? getAlbums() : Promise.resolve({ data: [] });
      })
      .then((albumsResponse) => {
        if (fetchedChanson?.albumId) {
          const matchedAlbum = (albumsResponse.data || []).find((a) => a.id === fetchedChanson.albumId);
          setAlbum(matchedAlbum || null);
        }
      })
      .catch(() => {
        setChanson(null);
        setAlbum(null);
      })
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <div className="alert alert-secondary">Chargement...</div>;
  if (!chanson) return <div className="alert alert-danger">Chanson non trouvée.</div>;

  return (
    <div>
      <div className="mb-4">
        <h1 className="h3">{chanson.titre}</h1>
        <p className="text-muted mb-1">ID: {chanson.id}</p>
        <p className="mb-1">Album: {album ? <strong>{album.titre}</strong> : `Album #${chanson.albumId}`}</p>
        {chanson.fichierAudio ? (
          <audio controls className="w-100 mb-3">
            <source src={`/uploads/musics/${chanson.fichierAudio}`} type="audio/mpeg" />
            Votre navigateur ne supporte pas l'audio.
          </audio>
        ) : (
          <div className="alert alert-warning">Aucun fichier audio attaché.</div>
        )}
        <div className="d-flex gap-2">
          <Link className="btn btn-outline-primary" to={`/chansons/${id}/edit`}>
            Modifier
          </Link>
          <Link className="btn btn-secondary" to="/chansons">
            Retour aux chansons
          </Link>
        </div>
      </div>
    </div>
  );
}
